@module generators  src=generators.lua  loc=468  sha=83df1a4  mode=namespace  self=generators

# Invariants & contracts
  @invariant  pure module, no state; a stage is fn(stream, host, params, ctx) -> { notes, delta }  @ 6
  @invariant  stream and host share one shape; stages read stream, host is the untouched original  @ 7
  @invariant  pb/ccs are absolute curves over the closed window (edge values seeded); pb val is cents  @ 9
  @invariant  ctx binds resolution, pbRangeCents, nextSameLaneNote(host), step(pitch,detune,n)  @ 10
  @invariant  periods are QN per the periodQN convention -- scalar or {num,den}  @ 11
  @invariant  mode is the stream fold -- replace overwrites the dest channel, augment adds to it  @ 14

# Shapes
  @shape  stream/host = { window={startppq,endppq}, chan, lane, id, notes={ {pitch,vel,detune,ppq,endppq},.. }, pas={ {ppq,pitch,vel},.. }, ccs={ [cc]={ {ppq,val,shape},.. } }, ats={ {ppq,val},.. }, pb={ {ppq,val,shape},.. } }  @ 8
  @shape  result = { notes = { {ppq,endppq,pitch,vel,detune}, ... }, delta = { {ppq,val,shape,[tension]}, ... } }  @ 12
  @shape  kinds[kind] = { expand, mode='replace'|'augment', dest='note'|'pb'|<cc>, label, defaults, fields }  @ 13
  @shape  fxPatterns (ds project) = { [name] = { kind='notes'|'curve', lengthPpq, root?=midiPitch, specs?={ {lane=1,ppq,endppq,pitch,vel,detune,delay,sample?},.. }, points?={ {ppq,val,shape,tension?},.. } } }  @ 17
  @shape  parkWindows -> { {evType='note'|'cc'|'pb', chan, cc?, startppq, endppq}, ... } (cc on cc windows only)  @ 442

